bool Registrations::validateJsonForCreation(const Json::Value &pJson, std::string &err)
{
    if(pJson.isMember("id"))
    {
        if(!validJsonOfField(0, "id", pJson["id"], err, true))
            return false;
    }
    if(pJson.isMember("full_name"))
    {
        if(!validJsonOfField(1, "full_name", pJson["full_name"], err, true))
            return false;
    }
    else
    {
        err="The full_name column cannot be null";
        return false;
    }
    if(pJson.isMember("phone"))
    {
        if(!validJsonOfField(2, "phone", pJson["phone"], err, true))
            return false;
    }
    else
    {
        err="The phone column cannot be null";
        return false;
    }
    if(pJson.isMember("email"))
    {
        if(!validJsonOfField(3, "email", pJson["email"], err, true))
            return false;
    }
    if(pJson.isMember("address"))
    {
        if(!validJsonOfField(4, "address", pJson["address"], err, true))
            return false;
    }
    if(pJson.isMember("note"))
    {
        if(!validJsonOfField(5, "note", pJson["note"], err, true))
            return false;
    }
    if(pJson.isMember("is_contacted"))
    {
        if(!validJsonOfField(6, "is_contacted", pJson["is_contacted"], err, true))
            return false;
    }
    if(pJson.isMember("contacted_by"))
    {
        if(!validJsonOfField(7, "contacted_by", pJson["contacted_by"], err, true))
            return false;
    }
    if(pJson.isMember("contacted_at"))
    {
        if(!validJsonOfField(8, "contacted_at", pJson["contacted_at"], err, true))
            return false;
    }
    if(pJson.isMember("created_at"))
    {
        if(!validJsonOfField(9, "created_at", pJson["created_at"], err, true))
            return false;
    }
    return true;
}
