std::vector<RegistrationInterests> Registrations::getInterests(const DbClientPtr &clientPtr) const {
    static const std::string sql = "select * from registration_interests where registration_id = $1";
    Result r(nullptr);
    {
        auto binder = *clientPtr << sql;
        binder << *id_ << Mode::Blocking >>
            [&r](const Result &result) { r = result; };
        binder.exec();
    }
    std::vector<RegistrationInterests> ret;
    ret.reserve(r.size());
    for (auto const &row : r)
    {
        ret.emplace_back(RegistrationInterests(row));
    }
    return ret;
}

void Registrations::getInterests(const DbClientPtr &clientPtr,
                                 const std::function<void(std::vector<RegistrationInterests>)> &rcb,
                                 const ExceptionCallback &ecb) const
{
    static const std::string sql = "select * from registration_interests where registration_id = $1";
    *clientPtr << sql
               << *id_
               >> [rcb = std::move(rcb)](const Result &r){
                   std::vector<RegistrationInterests> ret;
                   ret.reserve(r.size());
                   for (auto const &row : r)
                   {
                       ret.emplace_back(RegistrationInterests(row));
                   }
                   rcb(ret);
               }
               >> ecb;
}
